-- descriptions and helps
ZO_CreateStringId("MSAL_HELP_TITLE","|c999999Much Smarter AutoLoot Vous donne un controle total à travers votre looting, en rendant cela totalement automatiser par le simple paramétrage de vos préférence dans les filtres (Trad.fr by Ch4rli3)|r")
ZO_CreateStringId("MSAL_HELP_GEAR","|c999999Pour et seulement pour |ceeeeeeles équipements collectés qui n'ont pas été pillés|c999999, l'addon utilisera des filtres ultérieurs pour déterminer s'il faut ou non le piller|r")
ZO_CreateStringId("MSAL_HELP_MATERIAL","|c999999Tous les matériaux seront ramassés automatiquement lorsque vous aurez ESO+, quelle que soit la règle sur laquelle leurs filtres sont réglés, sauf si le matériau est volé|r")
ZO_CreateStringId("MSAL_HELP_MISC","|c999999Pour certains articles négociables de grande valeur, MSAL prend en charge la comparaison des prix via l'addon tiers (TTC, MM et ATT pris en charge). \nLes fonctions liées à ces l'addon sont automatiquement ajoutées à ce menu lorsque vous les activez|r")
ZO_CreateStringId("MSAL_HELP_MISC_TRIMED","|c999999Pour certains articles négociables de grande valeur, MSAL prend en charge la comparaison des prix via l'addon tiers (TTC, MM et ATT pris en charge). \nLorsqu'ils font référence à un tiers, les objets non échangeables de ce type seront pillés directement|r")
ZO_CreateStringId("MSAL_HELP_LIST","|c999999Les filtres %s / %s sont utiles lorsque vous avez besoin de règles spéciales, et ils ont une priorité plus élevée que les autres filtres. \nVous voulez exclure %s de la collection pour une vente ultérieure ? Ajoutez-le à %s ! (Cela ne vous empêchera pas de le prendre manuellement) Vous voulez %s mais pas les autres %s ? Ajoutez-le à %s ! \n\nCollez un lien vers l'élément dans les ajouts et entrez pour l'ajouter à la liste ; cliquez sur le menu déroulant des suppressions pour vérifier la liste, et cliquez sur l'un des éléments pour le supprimer!|r")
